const E=400;function i(n){const t=Number(n);return Number.isFinite(t)?t:null}function l(n,t){return n!=null&&t!=null&&Math.abs(n)<=90&&Math.abs(t)<=180}function h(n){const t=i(n==null?void 0:n.lat),a=i(n==null?void 0:n.lon);return l(t,a)?{lat:t,lon:a}:null}function f(n,t){if(!n||!t)return null;const a=i(n.lat),r=i(n.lon),o=i(t.lat),e=i(t.lon);if(!l(a,r)||!l(o,e))return null;const s=Math.PI/180,c=(o-a)*s,M=(e-r)*s,u=Math.sin(c/2)**2+Math.cos(a*s)*Math.cos(o*s)*Math.sin(M/2)**2;return 6371*(2*Math.atan2(Math.sqrt(u),Math.sqrt(1-u)))}function N(n,t,a=400){if(!n)return!1;if(!t)return!0;const r=f(n,t);return r==null?!1:r<=Number(a||400)}export{E as H,h as e,f as g,N as i};
